/// <reference types="react-scripts" />

import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import { RiskBadge } from './components/RiskBadge';
import { ExplanationCard } from './components/ExplanationCard';
import { RecommendationList } from './components/RecommendationList';

console.log('✅ App loading with all features');

// ============ SCAM ANALYZER ============
const ScamAnalyzer: React.FC = () => {
  const [text, setText] = React.useState('');
  const [isAnalyzing, setIsAnalyzing] = React.useState(false);
  const [result, setResult] = React.useState<any>(null);
  const [error, setError] = React.useState<string | null>(null);

  const handleAnalyze = async () => {
    if (!text.trim() || text.length < 10) {
      setError('Please enter at least 10 characters');
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('http://localhost:8000/api/scam/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text }),
      });
      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message || 'Failed to analyze');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h2 className="text-2xl font-bold mb-4">📱 Scam Message Analyzer</h2>
        <p className="text-gray-600 mb-4">Check WhatsApp messages, SMS, emails, and more</p>
        <textarea
          className="w-full h-32 p-4 border rounded-lg mb-4 focus:ring-2 focus:ring-blue-500"
          placeholder="Paste a suspicious message here..."
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
        <button
          className={`w-full py-3 px-6 rounded-lg font-semibold text-white ${
            isAnalyzing ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'
          }`}
          onClick={handleAnalyze}
          disabled={isAnalyzing}
        >
          {isAnalyzing ? 'Analyzing...' : '🔍 Analyze Message'}
        </button>
        {error && <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600">{error}</div>}
        {result && <ResultDisplay result={result} />}
      </div>
    </div>
  );
};

// ============ JOB ANALYZER ============
const JobAnalyzer: React.FC = () => {
  const [jobText, setJobText] = React.useState('');
  const [companyName, setCompanyName] = React.useState('');
  const [isAnalyzing, setIsAnalyzing] = React.useState(false);
  const [result, setResult] = React.useState<any>(null);
  const [error, setError] = React.useState<string | null>(null);

  const handleAnalyze = async () => {
    if (!jobText.trim() || jobText.length < 20) {
      setError('Please enter at least 20 characters');
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('http://localhost:8000/api/jobs/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ job_text: jobText, company_name: companyName }),
      });
      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message || 'Failed to analyze');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h2 className="text-2xl font-bold mb-4">💼 Job Advertisement Checker</h2>
        <p className="text-gray-600 mb-4">Check if a job ad is legitimate or a scam</p>
        <textarea
          className="w-full h-32 p-4 border rounded-lg mb-4 focus:ring-2 focus:ring-blue-500"
          placeholder="Paste the full job advertisement here..."
          value={jobText}
          onChange={(e) => setJobText(e.target.value)}
        />
        <input
          type="text"
          className="w-full p-3 border rounded-lg mb-4 focus:ring-2 focus:ring-blue-500"
          placeholder="Company Name (optional)"
          value={companyName}
          onChange={(e) => setCompanyName(e.target.value)}
        />
        <button
          className={`w-full py-3 px-6 rounded-lg font-semibold text-white ${
            isAnalyzing ? 'bg-gray-400' : 'bg-purple-600 hover:bg-purple-700'
          }`}
          onClick={handleAnalyze}
          disabled={isAnalyzing}
        >
          {isAnalyzing ? 'Analyzing...' : '🔍 Check Job'}
        </button>
        {error && <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600">{error}</div>}
        {result && <ResultDisplay result={result} />}
      </div>
    </div>
  );
};

// ============ URL CHECKER ============
const URLChecker: React.FC = () => {
  const [url, setUrl] = React.useState('');
  const [isChecking, setIsChecking] = React.useState(false);
  const [result, setResult] = React.useState<any>(null);
  const [error, setError] = React.useState<string | null>(null);

  const handleCheck = async () => {
    if (!url.trim()) {
      setError('Please enter a URL');
      return;
    }

    setIsChecking(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('http://localhost:8000/api/url/check', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });
      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message || 'Failed to check URL');
    } finally {
      setIsChecking(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch(status) {
      case 'Safe': return 'bg-green-100 text-green-800 border-green-200';
      case 'Suspicious': return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'Dangerous': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h2 className="text-2xl font-bold mb-4">🔗 URL Safety Checker</h2>
        <p className="text-gray-600 mb-4">Check if a website link is safe or suspicious</p>
        <input
          type="text"
          className="w-full p-3 border rounded-lg mb-4 focus:ring-2 focus:ring-blue-500"
          placeholder="Enter URL to check (e.g., https://example.com)"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
        />
        <button
          className={`w-full py-3 px-6 rounded-lg font-semibold text-white ${
            isChecking ? 'bg-gray-400' : 'bg-green-600 hover:bg-green-700'
          }`}
          onClick={handleCheck}
          disabled={isChecking}
        >
          {isChecking ? 'Checking...' : '🔍 Check URL'}
        </button>
        {error && <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600">{error}</div>}
        {result && (
          <div className="mt-6 space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold">URL Analysis</h3>
              <span className={`px-4 py-2 rounded-full text-sm font-semibold border ${getStatusColor(result.safety_status)}`}>
                {result.safety_status}
              </span>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-sm text-gray-600">Risk Score</p>
              <p className="text-2xl font-bold">{(result.risk_score * 100).toFixed(0)}%</p>
            </div>
            {result.indicators && result.indicators.length > 0 && (
              <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                <h4 className="font-semibold text-yellow-800 mb-2">⚠️ Suspicious Indicators:</h4>
                <ul className="list-disc pl-5 space-y-1">
                  {result.indicators.map((indicator: string, idx: number) => (
                    <li key={idx} className="text-yellow-700">{indicator}</li>
