// ============ IMAGE ANALYZER ============
const ImageAnalyzer: React.FC = () => {
  const [file, setFile] = React.useState<File | null>(null);
  const [preview, setPreview] = React.useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = React.useState(false);
  const [result, setResult] = React.useState<any>(null);
  const [error, setError] = React.useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => setPreview(reader.result as string);
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleAnalyze = async () => {
    if (!file) {
      setError('Please select an image');
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const formData = new FormData();
      formData.append('image', file);
      const response = await fetch('http://localhost:8000/api/image/analyze', {
        method: 'POST',
        body: formData,
      });
      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message || 'Failed to analyze image');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h2 className="text-2xl font-bold mb-4">🖼️ Image & Screenshot Analysis</h2>
        <p className="text-gray-600 mb-4">Upload a screenshot of a suspicious message</p>
        <input
          type="file"
          accept="image/*"
          className="w-full p-4 border-2 border-dashed rounded-lg mb-4 cursor-pointer"
          onChange={handleFileChange}
        />
        {preview && (
          <div className="mb-4">
            <img src={preview} alt="Preview" className="max-h-64 mx-auto rounded-lg border" />
          </div>
        )}
        <button
          className={`w-full py-3 px-6 rounded-lg font-semibold text-white ${
            isAnalyzing || !file ? 'bg-gray-400 cursor-not-allowed' : 'bg-pink-600 hover:bg-pink-700'
          }`}
          onClick={handleAnalyze}
          disabled={isAnalyzing || !file}
        >
          {isAnalyzing ? 'Analyzing...' : '🔍 Analyze Image'}
        </button>
        {error && <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600">{error}</div>}
        {result && <ResultDisplay result={result.analysis || result} />}
      </div>
    </div>
  );
};

// ============ MISINFORMATION DETECTOR ============
const MisinformationDetector: React.FC = () => {
  const [text, setText] = React.useState('');
  const [isAnalyzing, setIsAnalyzing] = React.useState(false);
  const [result, setResult] = React.useState<any>(null);
  const [error, setError] = React.useState<string | null>(null);

  const handleAnalyze = async () => {
    if (!text.trim() || text.length < 10) {
      setError('Please enter at least 10 characters');
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('http://localhost:8000/api/misinfo/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text }),
      });
      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message || 'Failed to analyze');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h2 className="text-2xl font-bold mb-4">📰 Misinformation Detector</h2>
        <p className="text-gray-600 mb-4">Check if news or social media content contains misinformation</p>
        <textarea
          className="w-full h-32 p-4 border rounded-lg mb-4 focus:ring-2 focus:ring-blue-500"
          placeholder="Paste a news article, social media post, or claim here..."
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
        <button
          className={`w-full py-3 px-6 rounded-lg font-semibold text-white ${
            isAnalyzing ? 'bg-gray-400' : 'bg-orange-600 hover:bg-orange-700'
          }`}
          onClick={handleAnalyze}
          disabled={isAnalyzing}
        >
          {isAnalyzing ? 'Analyzing...' : '🔍 Check Misinformation'}
        </button>
        {error && <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600">{error}</div>}
        {result && (
          <div className="mt-6 space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold">Analysis Results</h3>
              <RiskBadge level={result.risk_level} />
            </div>
            {result.suspicious_elements && result.suspicious_elements.length > 0 && (
              <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                <h4 className="font-semibold text-yellow-800 mb-2">⚠️ Suspicious Elements:</h4>
                <ul className="list-disc pl-5 space-y-1">
                  {result.suspicious_elements.map((item: any, idx: number) => (
                    <li key={idx} className="text-yellow-700">
                      <strong>"{item.word}"</strong> - {item.category}
                    </li>
                  ))}
                </ul>
              </div>
            )}
            <ExplanationCard explanations={result.explanation || []} />
            <RecommendationList recommendations={result.recommendations || []} />
          </div>
        )}
      </div>
    </div>
  );
};

